package com.google.gson.examples.android.model;

import static org.junit.jupiter.api.Assertions.assertEquals;

import java.lang.reflect.Constructor;

import org.junit.jupiter.api.Test;

class LineItemTest {

  @Test
  void testGetPriceInMicros() throws Exception {
    String name = "Test Item";
    int quantity = 5;
    long priceInMicros = 123456789L;
    String currencyCode = "USD";

    // Directly use the class instead of Class.forName to avoid ClassNotFoundException
    Class<LineItem> lineItemClass = LineItem.class;
    Constructor<LineItem> constructor = lineItemClass.getDeclaredConstructor(String.class, int.class, long.class, String.class);
    LineItem lineItem = constructor.newInstance(name, quantity, priceInMicros, currencyCode);

    long actualPriceInMicros = (long) lineItemClass.getMethod("getPriceInMicros").invoke(lineItem);

    assertEquals(priceInMicros, actualPriceInMicros);
  }
}
